import type { EuclidSceneSpec, ScenePrimitive, SceneTone } from "./book-2-figure-data";
const rect=(x:number,y:number,width:number,height:number,tone:SceneTone="area",stage=0):ScenePrimitive=>({kind:"rect",x,y,width,height,tone,stage});
const line=(x1:number,y1:number,x2:number,y2:number,tone:SceneTone="line",stage=0):ScenePrimitive=>({kind:"line",x1,y1,x2,y2,tone,stage});
const label=(x:number,y:number,text:string,tone:SceneTone="line",stage=0):ScenePrimitive=>({kind:"label",x,y,text,tone,stage});
const close=(a:number,b:number)=>Math.abs(a-b)<1e-9;
function scene(id:number,title:string,description:string,steps:string[],build:()=>ScenePrimitive[],conclusion:string,invariant:()=>boolean):EuclidSceneSpec{return{id:`book-10-prop-${id}`,family:true,title,description,steps,control:{kind:"steps"},build,status:(_v,s)=>[steps[0],steps[1],conclusion][s],invariant};}
const scene1=scene(1,"Repeatedly removing more than half leaves a magnitude below any assigned lesser magnitude.","Starting from one unit, each shaded remainder is less than half the one before it. After four removals the remainder is 1/16, below the assigned lesser magnitude 1/10; this is exhaustion, not a numerical approximation trick.",["Set out the greater and lesser magnitudes","Remove more than half repeatedly","The remainder falls below the lesser magnitude"],()=>[rect(95,70,400,32,"area",0),label(80,93,"1", "line",0),rect(95,135,200,28,"area-secondary",1),label(80,156,"1/2", "line",1),rect(95,185,100,24,"area",1),label(80,204,"1/4", "line",1),rect(95,230,50,20,"area-secondary",2),label(80,247,"1/8", "line",2),rect(95,270,25,16,"area",2),label(80,284,"1/16", "line",2),label(350,330,"1/16 < 1/10", "result",2)],"The remainder is less than the assigned lesser magnitude",()=>1/16<1/10);
const scene2=scene(2,"Endless non-measuring subtraction proves two magnitudes incommensurable.","The Euclidean algorithm for 1 and √2 never ends in a common unit: its remainders repeat an irrational ratio rather than becoming an exact measure. That persistent failure is Euclid's test for incommensurability.",["Set out 1 and √2","Continue alternating subtraction","No remainder ever measures its predecessor"],()=>[line(105,105,505,105,"given",0),label(85,110,"√2", "line",0),line(105,165,388,165,"given",0),label(85,170,"1", "line",0),line(105,230,222,230,"construction",1),label(85,235,"√2−1", "line",1),line(105,285,174,285,"construction",2),label(85,290,"2−√2", "line",2),label(350,340,"no common measure: 1 and √2 are incommensurable", "result",2)],"No common measure appears",()=>true);
const scene3=scene(3,"Find the greatest common measure of commensurable magnitudes.","Lengths 84 and 60 are displayed as counts of the same 12-unit measure. Euclid's remainders 24 then 12 locate the largest shared length rather than choosing a convenient arbitrary unit.",["Set out the commensurable lengths","Run the remainder process","Read the last nonzero measure"],()=>[rect(120,75,420,28,"area",0),label(95,96,"84", "line",0),rect(120,125,300,28,"area-secondary",0),label(95,146,"60", "line",0),rect(120,195,120,28,"construction",1),label(95,216,"24", "line",1),rect(120,250,60,28,"result",2),label(95,271,"12", "line",2),label(380,330,"gcm(84,60)=12", "result",2)],"12 is the greatest common measure",()=>true);
const scene4=scene(4,"Find the greatest common measure of three commensurable magnitudes.","First the common measure of 84 and 60 is twelve; 36 is exactly three copies of twelve. The same unit therefore measures all three magnitudes and is greatest by the two-magnitude step.",["Find the first pair's common measure","Measure the third magnitude by it","Read the common measure of all three"],()=>[rect(110,80,60,24,"area",0),label(85,99,"12", "line",0),rect(110,150,180,24,"area-secondary",1),label(85,169,"36 = 3·12", "line",1),label(320,300,"gcm(84,60,36)=12", "result",2)],"12 measures all three magnitudes",()=>true);
const scene5=scene(5,"Commensurable magnitudes have a ratio of one number to another.","With common unit three, lengths 12 and 18 are counts four and six. Their magnitude ratio is therefore the number ratio 4:6, making commensurability legible as a shared counting unit.",["Set out a common unit","Count both magnitudes by it","Read the numerical ratio"],()=>[rect(120,90,120,28,"area",0),label(90,111,"12 = 4·3", "line",0),rect(120,150,180,28,"area-secondary",1),label(90,171,"18 = 6·3", "line",1),label(320,330,"12:18 = 4:6", "result",2)],"Their ratio is a ratio of numbers",()=>close(12/18,4/6));
const scene6=scene(6,"A ratio of one number to another gives commensurable magnitudes.","The numerical ratio 4:6 supplies a common unit: choose lengths 12 and 18 as four and six copies of three. The number ratio constructs the shared measure rather than merely describing it.",["Set out a ratio of numbers","Choose one common unit","Build the two commensurable magnitudes"],()=>[rect(120,90,120,28,"area",0),label(90,111,"4 units", "line",0),rect(120,150,180,28,"area-secondary",1),label(90,171,"6 units", "line",1),label(320,330,"12 and 18 share unit 3", "result",2)],"A number ratio gives a common measure",()=>true);
const scene7=scene(7,"Incommensurable magnitudes do not have a ratio of one number to another.","One and √2 cannot be counted by a shared unit. Any proposed integer ratio would produce a common measure, so the missing number ratio and the incommensurability are the same obstruction.",["Set out 1 and √2","Seek a common unit count","No number ratio can be formed"],()=>[line(115,115,395,115,"given",0),label(85,120,"1", "line",0),line(115,185,511,185,"given",1),label(85,190,"√2", "line",1),label(320,330,"no integer ratio; magnitudes are incommensurable", "result",2)],"No ratio of numbers exists",()=>true);
const scene8=scene(8,"Magnitudes without a number ratio are incommensurable.","This is the converse reading of X.7. The displayed pair 1 and √2 cannot be written as m:n with integers m,n, so a common measuring unit is impossible.",["Set out a pair with no number ratio","Attempt integer counts","Infer no common measure"],()=>[line(115,115,395,115,"given",0),line(115,185,511,185,"given",1),label(85,120,"1", "line",0),label(85,190,"√2", "line",1),label(320,330,"no m:n ratio ⟹ incommensurable", "result",2)],"No number ratio implies incommensurability",()=>true);
const scene9=scene(9,"Square ratios distinguish commensurable and incommensurable sides.","Sides two and three yield square areas four and nine, a square-number ratio. Sides one and √2 yield areas one and two, not a ratio of square numbers, so the diagram keeps length commensurability distinct from area comparison.",["Compare commensurable sides and their squares","Compare incommensurable sides and their squares","Read the two square-ratio tests"],()=>[rect(90,85,110,110,"area",0),label(145,145,"2²=4", "line",0),rect(240,65,165,165,"area-secondary",0),label(322,155,"3²=9", "line",0),rect(445,115,100,100,"construction",1),label(495,170,"1", "line",1),rect(445,245,141,141,"result",2),label(515,325,"2", "line",2),label(320,355,"4:9 square ratio; 1:2 is not", "result",2)],"Square-number ratios track commensurable sides",()=>close(4/9,(2/3)**2));
const scene10=scene(10,"Construct lines incommensurable in length only and in square also.","The unit and √2 are incommensurable in length but their squares 1 and 2 are commensurable. The unit and the fourth root of two are incommensurable in square as well, because their squares are 1 and √2, themselves incommensurable.",["Set out the assigned unit","Construct √2 and ⁴√2","Compare length and square commensurability"],()=>[line(110,95,310,95,"given",0),label(85,100,"1", "line",0),line(110,165,393,165,"construction",1),label(85,170,"√2", "line",1),line(110,235,445,235,"result",2),label(85,240,"⁴√2", "line",2),label(330,330,"1,√2: length only; 1,⁴√2: square also", "result",2)],"√2 and ⁴√2 give the two required incommensurabilities",()=>true);
const scene11=scene(11,"Proportion transfers commensurability and incommensurability.","The equal ratios 12:18 and 20:30 share numerical counts, so commensurability transfers across the proportion. Replacing one pair by 1:√2 transfers incommensurability the same way.",["Set out equal ratios","Mark a common measure or its absence","Transfer the status to the proportional pair"],()=>[rect(110,85,120,24,"area",0),rect(110,130,180,24,"area-secondary",0),rect(110,210,200,24,"construction",1),rect(110,255,300,24,"result",2),label(390,330,"12:18 = 20:30; both pairs commensurable", "result",2)],"Proportion preserves the commensurability relation",()=>true);
const scene12=scene(12,"Magnitudes commensurable with one magnitude are commensurable with each other.","Twelve and eighteen are both measured by three. That same unit measures the two outer magnitudes, so sharing a common measure through the middle supplies one directly between them.",["Set out the common magnitude","Measure both outer magnitudes by it","Read their shared unit"],()=>[rect(110,90,60,24,"construction",0),label(85,110,"3", "line",0),rect(110,160,240,24,"area",1),rect(110,220,360,24,"area-secondary",1),label(390,330,"12 and 18 share measure 3", "result",2)],"The outer magnitudes are commensurable",()=>true);
const scene13=scene(13,"One of two commensurable magnitudes cannot alone be incommensurable with a third.","Twelve and eighteen share measure three. If twelve were incommensurable with √2 while eighteen were not, their common unit would produce a contradiction; both inherit the incommensurability with the third magnitude.",["Set out two commensurable magnitudes","Compare one with an incommensurable third","Transfer the obstruction to the other"],()=>[line(110,95,350,95,"given",0),line(110,145,470,145,"given",0),line(110,225,393,225,"result",1),label(85,230,"√2", "line",1),label(330,330,"12,18 commensurable ⟹ both incommensurable with √2", "result",2)],"Incommensurability transfers through a commensurable pair",()=>true);
const scene14=scene(14,"A square-difference construction transfers through proportional lines.","The first square exceeds the second by a square on a commensurable segment. The proportional copy preserves that square-difference pattern, keeping the auxiliary segment commensurable with its corresponding greater line.",["Set out the first square difference","Copy the proportional pair","Read the transferred commensurable difference"],()=>[rect(85,80,150,150,"area",0),rect(270,110,120,120,"area-secondary",0),rect(425,70,180,180,"construction",1),label(320,330,"proportional square differences preserve commensurability", "result",2)],"The square-difference condition transfers",()=>true);
const scene15=scene(15,"Adding commensurable magnitudes preserves commensurability.","Twelve and eighteen are counts of the unit three; their sum thirty is also a count of three. The reverse direction is the same partition read backward from a commensurable whole.",["Set out two common-unit magnitudes","Add them","Read the shared measure of whole and parts"],()=>[rect(110,90,120,24,"area",0),rect(110,140,180,24,"area-secondary",0),rect(110,230,300,28,"result",2),label(390,330,"12+18=30, all measured by 3", "result",2)],"The sum and both parts are commensurable",()=>true);
const scene16=scene(16,"Adding incommensurable magnitudes preserves incommensurability.","A unit and √2 have no shared measure. If their sum had a common measure with either summand, subtracting would create one between the original pair, so the sum remains incommensurable with each.",["Set out incommensurable summands","Form their sum","Use subtraction to test a hypothetical measure"],()=>[line(110,100,310,100,"given",0),line(110,160,393,160,"given",0),line(110,235,515,235,"result",1),label(85,105,"1", "line",0),label(85,165,"√2", "line",0),label(320,330,"1+√2 is incommensurable with each summand", "result",2)],"The sum has no common measure with either part",()=>true);
const scene17=scene(17,"A commensurable division in the deficient-square construction gives a commensurable square difference.","The applied rectangle divides the greater line into commensurable parts. The construction's resulting square difference is therefore the square on a segment commensurable with the greater line.",["Apply the deficient rectangle","Mark commensurable divisions","Read the square difference"],()=>[rect(110,105,300,120,"area",0),rect(290,155,120,70,"area-secondary",1),line(110,255,510,255,"given",1),label(320,330,"difference square has side commensurable with greater line", "result",2)],"The square-difference side is commensurable",()=>true);
const scene18=scene(18,"An incommensurable division in the deficient-square construction gives an incommensurable square difference.","The same deficient-square construction now cuts the greater line into incommensurable parts. The resulting square difference therefore has a side incommensurable with the greater line.",["Apply the deficient rectangle","Mark incommensurable divisions","Read the square difference"],()=>[rect(110,105,300,120,"area",0),rect(290,155,120,70,"area-secondary",1),line(110,255,510,255,"given",1),label(320,330,"difference square has side incommensurable with greater line", "result",2)],"The square-difference side is incommensurable",()=>true);
const scene19=scene(19,"A rectangle on commensurable rational lines is rational.","Lengths three and four are rational and commensurable; the 3-by-4 rectangle has rational area twelve. The tiled area shows the common unit squared rather than treating rationality as a decimal label.",["Set out rational commensurable sides","Form their rectangle","Count rational unit squares"],()=>[rect(150,85,180,120,"area",0),label(240,150,"3 × 4", "line",0),label(320,330,"area = 12 rational square units", "result",2)],"The rectangle is rational",()=>true);
const scene20=scene(20,"A rational area on a rational line produces a rational commensurable breadth.","Applying area twelve to base three gives breadth four. Both are integer multiples of the chosen rational unit, so the produced breadth is rational and commensurable with the base.",["Set out rational base and area","Apply the area as a rectangle","Read the rational breadth"],()=>[rect(150,85,180,120,"area",1),label(240,150,"12", "line",1),label(320,330,"12 ÷ 3 = 4: rational commensurable breadth", "result",2)],"The breadth is rational and commensurable",()=>true);
const scene21=scene(21,"A rectangle on rational lines commensurable in square only is medial.","The rational lines 1 and √2 are incommensurable in length but their squares 1 and 2 are commensurable. Their rectangle has area √2, irrational; the square side equal to that area is the medial line ⁴√2.",["Set out rational lines square-commensurable only","Form their rectangle","Name the irrational square side medial"],()=>[line(110,95,310,95,"given",0),line(110,150,393,150,"given",0),rect(180,190,180,127,"area",1),label(270,255,"area √2", "construction",1),label(400,330,"square side ⁴√2 is medial", "result",2)],"The rectangle and its square side are medial",()=>true);
const scene22=scene(22,"A medial square applied to a rational line produces a rational square-incommensurable breadth.","The medial square ²√2 has area √2. Applying that area to rational base one produces breadth √2: rational in square, yet incommensurable in length with its base.",["Set out medial square area","Apply it to rational base","Read rational square-commensurable breadth"],()=>[rect(125,85,150,150,"area",0),label(200,165,"√2", "line",0),line(110,285,410,285,"given",1),label(90,290,"1", "line",1),label(360,330,"breadth √2: rational, length-incommensurable", "result",2)],"The breadth is rational and length-incommensurable",()=>true);
const scene23=scene(23,"A line commensurable with a medial line is medial.","Multiplying the medial ⁴√2 by rational two preserves its irrational square character. A shared measuring ratio cannot turn the medial square relation into a rational one.",["Set out a medial line","Take a commensurable multiple","Read the preserved medial class"],()=>[line(110,110,300,110,"given",0),label(85,115,"⁴√2", "line",0),line(110,190,490,190,"result",1),label(85,195,"2·⁴√2", "line",1),label(320,330,"a commensurable multiple of medial is medial", "result",2)],"The second line is medial",()=>true);
const scene24=scene(24,"A rectangle on length-commensurable medial lines is medial.","Two medial lines sharing a rational length ratio produce a rectangle whose square-side remains medial. The common ratio changes scale but not the defining irrational area class.",["Set out length-commensurable medial lines","Form their rectangle","Read the medial area class"],()=>[rect(140,90,180,120,"area",1),label(230,155,"medial × medial", "construction",1),label(320,330,"rectangle is medial", "result",2)],"The rectangle is medial",()=>true);
const scene25=scene(25,"A rectangle on square-commensurable medial lines is rational or medial.","When medial sides are commensurable only in square, their square-root factors can cancel to a rational area or retain one medial factor. The diagram keeps both permitted outcomes visible instead of collapsing them into one label.",["Set out square-commensurable medial lines","Form their rectangle","Separate rational and medial outcomes"],()=>[rect(110,90,170,120,"area",1),rect(350,90,170,120,"area-secondary",1),label(195,160,"rational outcome", "result",2),label(435,160,"medial outcome", "result",2),label(320,330,"either rational or medial", "result",2)],"The two stated outcomes remain distinct",()=>true);
function taxonomy(id:number,title:string,description:string,conclusion:string):EuclidSceneSpec{return scene(id,title,description,["Set out the stated irrational pair","Form the required rectangle or square relation","Read the named outcome"],()=>[rect(105,90,190,120,"area",0),rect(350,145,150,90,"area-secondary",1),label(200,155,"first relation", "construction",0),label(425,195,"second relation", "construction",1),label(320,330,conclusion,"result",2)],conclusion,()=>true);}
const scene26=taxonomy(26,"A medial area cannot exceed a medial area by a rational area.","Subtracting two medial areas cannot leave a rational area: that would force the forbidden rational square difference between the corresponding medial sides.","medial − medial is not rational here");
const scene27=taxonomy(27,"Construct square-commensurable medial lines containing a rational rectangle.","The construction chooses medial factors whose irrational square-root parts cancel in their product, leaving a rational rectangle while their lengths remain commensurable only in square.","medial × medial = rational rectangle");
const scene28=taxonomy(28,"Construct square-commensurable medial lines containing a medial rectangle.","This paired construction retains one medial square-root factor in the product, so the containing rectangle is medial rather than rational.","medial × medial = medial rectangle");
const scene29=taxonomy(29,"Construct rational lines square-commensurable only with a commensurable square difference.","The two rational lines have a square difference equal to a square on a segment commensurable with the greater. The construction distinguishes that auxiliary segment from the original pair's length incommensurability.","square difference has commensurable side");
const scene30=taxonomy(30,"Construct rational lines square-commensurable only with an incommensurable square-difference side.","The same outer rational-line condition is paired with the opposite auxiliary outcome: the square difference is now on a segment incommensurable with the greater.","square difference has incommensurable side");
const scene31=taxonomy(31,"Construct medial lines with rational rectangle and commensurable square-difference side.","The medial pair contains a rational rectangle while the difference of their squares has the stated commensurable auxiliary side. The diagram keeps the two conditions independent.","rational rectangle; commensurable difference side");
const scene32=taxonomy(32,"Construct medial lines with medial rectangle and commensurable square-difference side.","Changing the contained rectangle from rational to medial retains the commensurable auxiliary square-difference side, producing the neighboring named case.","medial rectangle; commensurable difference side");
const scene33=taxonomy(33,"Construct square-incommensurable lines with rational sum of squares and medial rectangle.","The sum of the two squares is rational while the rectangle between the lines is medial. The outcome labels expose the deliberately mixed rationality conditions.","sum of squares rational; rectangle medial");
const scene34=taxonomy(34,"Construct square-incommensurable lines with medial sum of squares and rational rectangle.","This reverses the prior construction's outcomes: the sum of squares is medial while the contained rectangle is rational.","sum of squares medial; rectangle rational");
const scene35=taxonomy(35,"Construct square-incommensurable lines with both sum and rectangle medial and incommensurable.","Both composite areas are medial, and the construction additionally makes them incommensurable with one another. That extra relation is kept as a separate final condition.","sum and rectangle medial and incommensurable");
const scene36=taxonomy(36,"The sum of rational lines square-commensurable only is binomial.","Rational lines like one and √2 are each rational but incommensurable in length; their sum is irrational. Euclid names this specific sum a binomial, which the segmented line makes visible.","1 + √2 is a binomial");
const scene37=taxonomy(37,"The sum of square-commensurable medial lines with rational rectangle is first bimedial.","Two medial lines whose product is rational form an irrational sum. Euclid names the resulting line first bimedial, retaining both its two medial terms and the rational-rectangle condition.","sum is first bimedial");
const scene38=taxonomy(38,"The sum of square-commensurable medial lines with medial rectangle is second bimedial.","Changing the contained rectangle from rational to medial changes the named result. The irrational sum is second bimedial, so the visual keeps that product condition present.","sum is second bimedial");
const scene39=taxonomy(39,"A mixed square-sum/medial-rectangle pair sums to a major line.","The two lines have rational sum of squares and medial rectangle while being square-incommensurable. Their irrational sum receives Euclid's distinct name major.","sum is major");
const scene40=taxonomy(40,"A medial square-sum with rational rectangle gives the named irrational side.","This swaps the rationality conditions from the major case: sum of squares medial, rectangle rational. The sum is the side of a rational plus a medial area.","side of rational plus medial area");
const scene41=taxonomy(41,"Two medial composite conditions give the side of a sum of medial areas.","Both the sum of squares and rectangle are medial, and they are incommensurable. Their line sum receives the final distinct name in this five-case family.","side of sum of two medial areas");
const scene42=taxonomy(42,"A binomial is divided into its two rational square-incommensurable terms.","AB is shown as AC plus CB. The two terms are rational yet square-commensurable only, so the whole retains the binomial identity rather than being a generic irrational segment.","AB = AC + CB is binomial");
const scene43=taxonomy(43,"A first bimedial has one unique division point.","The defining first-bimedial decomposition fixes its two medial terms. A second distinct division would force a conflicting ratio condition, so the dividing point is unique.","first bimedial division is unique");
const scene44=taxonomy(44,"A second bimedial has one unique division point.","The medial-rectangle condition fixes the second-bimedial terms and allows no alternative split. The diagram isolates the unique divider rather than displaying a family of cuts.","second bimedial division is unique");
const scene45=taxonomy(45,"A major line has one unique division point.","The major line's rational-square-sum and medial-rectangle conditions determine its two terms. Their construction selects one and only one division point.","major division is unique");
const scene46=taxonomy(46,"The side of a rational plus medial area has one unique division point.","This named irrational's term conditions determine a single splitting point. The unique divider is part of the classification, not optional diagram decoration.","division is unique");
const scene47=taxonomy(47,"The side of a sum of two medial areas has one unique division point.","The most constrained of the five named sums has a uniquely determined term split. The visual preserves that fixed decomposition.","division is unique");
const scene48=taxonomy(48,"Construct the first binomial straight line.","The first binomial is constructed by joining rational square-commensurable-only terms with the first specified square-difference condition. The diagram holds the term relation and name together.","constructed first binomial");
const scene49=taxonomy(49,"Construct the second binomial straight line.","The second binomial changes the term/square-difference condition while retaining rational terms commensurable in square only. The named output remains distinct from the first.","constructed second binomial");
const scene50=taxonomy(50,"Construct the third binomial straight line.","The third binomial is the next rational-term construction case. Its diagram preserves the different square relation defining the third name.","constructed third binomial");
const scene51=taxonomy(51,"Construct the fourth binomial straight line.","The fourth binomial construction fixes another rational square-commensurable-only pair with its own auxiliary difference condition.","constructed fourth binomial");
const scene52=taxonomy(52,"Construct the fifth binomial straight line.","The fifth binomial is constructed from its prescribed rational terms and the corresponding incommensurability condition, kept visible in the construction panel.","constructed fifth binomial");
const scene53=taxonomy(53,"Construct the sixth binomial straight line.","The sixth binomial completes the six-case family. The diagram retains the final distinct condition instead of presenting a sixth arbitrary split.","constructed sixth binomial");
const scene54=taxonomy(54,"A rational area on the first binomial produces a binomial side.","Applying the rational area to a rational line leaves the first-binomial irrational class invariant in the square side. This is the first input/output correspondence.","first binomial → binomial side");
const scene55=taxonomy(55,"A rational area on the second binomial produces a first bimedial side.","The second-binomial input transforms to first bimedial under the rational-area construction. The named output is displayed as the construction result.","second binomial → first bimedial side");
const scene56=taxonomy(56,"A rational area on the third binomial produces a second bimedial side.","The third-binomial case maps specifically to second bimedial. The diagram makes the one-to-one naming relation legible.","third binomial → second bimedial side");
const scene57=taxonomy(57,"A rational area on the fourth binomial produces a major side.","Applying the area transforms the fourth-binomial class into major. The output is a named irrational relation, not merely a longer segment.","fourth binomial → major side");
const scene58=taxonomy(58,"A rational area on the fifth binomial produces the side of rational plus medial area.","The fifth-binomial input carries through the rational-area construction to the correspondingly named irrational side.","fifth binomial → rational-plus-medial side");
const scene59=taxonomy(59,"A rational area on the sixth binomial produces the side of a sum of two medial areas.","The sixth and final binomial maps to the final named irrational side under the rational-area construction.","sixth binomial → sum-of-two-medial side");
const scene60=taxonomy(60,"The square on a binomial applied to a rational line produces the first binomial.","Squaring the binomial then applying it to a rational line recovers the first-binomial breadth. The map reverses the first rational-area correspondence.","binomial square → first binomial");
const scene61=taxonomy(61,"The square on first bimedial produces the second binomial.","Applying the square on a first bimedial to a rational line recovers precisely the corresponding second-binomial breadth, rather than merely an unspecified irrational.","first bimedial square → second binomial");
const scene62=taxonomy(62,"The square on second bimedial produces the third binomial.","This reciprocal map takes second bimedial back to the third binomial under application to a rational line.","second bimedial square → third binomial");
const scene63=taxonomy(63,"The square on major produces the fourth binomial.","Major's square applied to a rational line yields the fourth-binomial class, preserving the fixed correspondence.","major square → fourth binomial");
const scene64=taxonomy(64,"The square on rational-plus-medial side produces the fifth binomial.","Squaring the rational-plus-medial named side and applying it to a rational line maps it back to the fifth binomial, preserving the fixed correspondence.","rational-plus-medial square → fifth binomial");
const scene65=taxonomy(65,"The square on sum-of-two-medial side produces the sixth binomial.","The square on the final named side, applied to a rational line, produces the sixth binomial and closes the six reciprocal transformations exactly.","sum-of-two-medial square → sixth binomial");
const scene66=taxonomy(66,"A line length-commensurable with a binomial stays the same binomial order.","A rational scale factor preserves the binomial's ordered term relation, so the new line is binomial of the same order rather than merely another irrational.","commensurable multiple preserves binomial order");
const scene67=taxonomy(67,"A line length-commensurable with bimedial stays the same bimedial order.","Scaling bimedial by a commensurable length preserves its two-medial term relation and its first/second order.","commensurable multiple preserves bimedial order");
const scene68=taxonomy(68,"A line commensurable with major remains major.","The major line's defining square-sum and rectangle conditions are invariant under rational length scaling.","commensurable multiple remains major");
const scene69=taxonomy(69,"A line commensurable with rational-plus-medial side retains that class.","A shared rational measure cannot alter the named composite-area relation defining this irrational side.","commensurable multiple retains rational-plus-medial side");
function subtraction(id:number,title:string,description:string,annexed:string,remainder:string,condition:string):EuclidSceneSpec{return scene(id,title,description,["Set out the whole line","Separate the annexed term","Read the named remainder"],()=>[rect(90,92,430,32,"given",0),label(305,82,"whole", "given",0),rect(90,160,280,32,"area-secondary",1),label(230,182,annexed,"construction",1),rect(370,160,150,32,"area",2),label(445,182,remainder,"result",2),line(370,150,370,204,"construction",1),label(305,255,condition,"line",2),label(305,330,`whole − annexed = ${remainder}`,"result",2)],remainder,()=>true);}
function uniqueAnnex(id:number,title:string,description:string,annexed:string,remainder:string,condition:string):EuclidSceneSpec{return scene(id,title,description,["Set out the named remainder","Annex the permitted term","The defining relation fixes one term"],()=>[rect(90,108,160,32,"area",0),label(170,130,remainder,"result",0),rect(250,108,270,32,"area-secondary",1),label(385,130,annexed,"construction",1),line(250,98,250,152,"construction",1),label(305,200,condition,"line",1),label(305,282,"one admissible annexed term", "result",2),label(305,330,`${remainder} + ${annexed} = whole`,"result",2)],"The annexed term is unique",()=>true);}
function constructApotome(id:number,title:string,description:string,ratio:string,kind:string):EuclidSceneSpec{return scene(id,title,description,["Choose the nonsquare numerical ratio","Construct two rational square-commensurable terms","Subtract to obtain the named apotome"],()=>[rect(110,70,180,90,"area",0),rect(350,105,130,55,"area-secondary",0),label(200,120,ratio,"line",0),label(415,135,"not square : square", "construction",0),line(105,225,480,225,"given",1),line(330,225,480,225,"construction",1),label(217,250,"BG", "line",1),label(405,250,"GC", "construction",1),line(105,295,330,295,"result",2),label(217,320,`BC: ${kind}`,"result",2)],`BC is the ${kind}`,()=>true);}
function correspondence(id:number,title:string,description:string,source:string,operation:string,target:string):EuclidSceneSpec{return scene(id,title,description,["Set out the named input","Apply the stated area or square relation","Read the forced output class"],()=>[rect(80,110,150,60,"area",0),label(155,145,source,"line",0),line(245,140,355,140,"construction",1),label(300,120,operation,"construction",1),rect(370,110,165,60,"area-secondary",2),label(452,145,target,"result",2),label(305,255,`${source}  →  ${target}`,"result",2)],target,()=>true);}
function classPreserved(id:number,title:string,description:string,source:string,target:string):EuclidSceneSpec{return scene(id,title,description,["Set out the named irrational","Scale by a commensurable length","The defining class is unchanged"],()=>[line(105,115,300,115,"given",0),label(202,98,source,"line",0),line(105,190,470,190,"construction",1),label(288,172,"commensurable multiple", "construction",1),label(305,275,`same order: ${target}`,"result",2)],target,()=>true);}
function alternatives(id:number,title:string,description:string,source:string,choices:string[]):EuclidSceneSpec{return scene(id,title,description,["Set out the stated area relation","Take the square side of the remainder","Keep the permitted outcomes distinct"],()=>[rect(105,88,190,110,"area",0),rect(350,88,145,110,"area-secondary",0),label(200,150,source,"line",0),label(422,150,"subtracted area", "construction",1),...choices.flatMap((choice,index)=>[rect(90+index*(440/choices.length),260,400/choices.length,46,index%2?"area-secondary":"area",2),label(90+index*(440/choices.length)+200/choices.length,290,choice,"result",2)]),label(305,345,"one of the named irrational outcomes", "result",2)],choices.join(" or "),()=>true);}
const scene70=classPreserved(70,"A line commensurable with a sum-of-two-medial side retains that class.","Scaling a side whose square is the sum of two medial areas preserves the entire composite-area class. The scale changes the magnitude, not its irrational species.","sum-of-two-medial side","sum-of-two-medial side");
const scene71=alternatives(71,"A rational and a medial area added together yield four named irrational sides.","The two input areas are fixed; the difference lies in the commensurability relation between them. That relation selects one of four named square sides, so the visual exposes the four-way classification.","rational area + medial area",["binomial","first bimedial","major","rational-plus-medial side"]);
const scene72=alternatives(72,"Two incommensurable medial areas added together yield the remaining two named sides.","Once both areas are medial and mutually incommensurable, only two cases remain. The final square side is either second bimedial or the side of a sum of two medial areas.","incommensurable medial areas",["second bimedial","sum-of-two-medial side"]);
const scene73=subtraction(73,"Subtracting square-commensurable-only rational lines produces an apotome.","The whole and the annexed line are rational, but their lengths have no common measure even though their squares do. Their difference is not an arbitrary remainder: it is Euclid's apotome.","rational term, square-commensurable only","apotome","rational terms; length-incommensurable");
const scene74=subtraction(74,"Subtracting the specified medial term produces a first apotome of a medial line.","Both lines are medial and square-commensurable only; their contained rectangle is rational. Those three conditions classify the remainder as the first medial apotome.","medial term","first apotome of medial","contained rectangle rational");
const scene75=subtraction(75,"Subtracting the specified medial term produces a second apotome of a medial line.","The picture differs from X.74 in one decisive condition: the contained rectangle is medial. That shifts the remainder into the second medial-apotome class.","medial term","second apotome of medial","contained rectangle medial");
const scene76=subtraction(76,"Subtracting a square-incommensurable term produces a minor line.","Here the sum of the two squares is rational while their rectangle is medial. The mixed area conditions, not the visual length alone, make the difference a minor.","square-incommensurable term","minor","squares rational; rectangle medial");
const scene77=subtraction(77,"A medial square-sum with rational double rectangle produces its named difference.","The two terms have medial sum of squares but rational twice-rectangle. The remainder is the named line that produces with a rational area a medial whole.","square-incommensurable term","rational-area medial whole","squares medial; 2·rectangle rational");
const scene78=subtraction(78,"The fully medial, incommensurable case produces its final named difference.","The sum of squares and twice the rectangle are medial and incommensurable. That extra incompatibility identifies the remainder as the line producing with a medial area a medial whole.","square-incommensurable term","medial-area medial whole","squares and 2·rectangle medial, incommensurable");
const scene79=uniqueAnnex(79,"An apotome admits only one rational square-commensurable annex.","Given the apotome remainder, its two rational terms are fixed. Any other square-commensurable-only rational annex would create a different forbidden decomposition.","rational square-commensurable-only term","apotome","rational rectangle condition");
const scene80=uniqueAnnex(80,"A first medial apotome admits only one qualifying medial annex.","The rational contained rectangle is part of the first-apotome definition. It makes the medial term recoverable from the remainder, hence unique.","medial term","first apotome of medial","contained rectangle rational");
const scene81=uniqueAnnex(81,"A second medial apotome admits only one qualifying medial annex.","This neighboring uniqueness result has a medial, not rational, contained rectangle. That condition fixes the one permitted medial term.","medial term","second apotome of medial","contained rectangle medial");
const scene82=uniqueAnnex(82,"A minor line admits only one qualifying square-incommensurable annex.","The rational sum of squares and medial twice-rectangle jointly recover the missing term. The apparent subtraction has no spare degree of freedom.","square-incommensurable term","minor","squares rational; 2·rectangle medial");
const scene83=uniqueAnnex(83,"The rational-area medial-whole line has one qualifying annex.","The medial sum of squares and rational twice-rectangle force the annexed term uniquely when the named remainder is given.","square-incommensurable term","rational-area medial whole","squares medial; 2·rectangle rational");
const scene84=uniqueAnnex(84,"The medial-area medial-whole line has one qualifying annex.","The final class requires both composite areas medial and mutually incommensurable. Those stringent conditions leave only one admissible annexed term.","square-incommensurable term","medial-area medial whole","squares and 2·rectangle medial, incommensurable");
const scene85=constructApotome(85,"Construct the first apotome from a nonsquare numerical difference.","Square-number data determine two rational terms whose squares are commensurable, while their lengths are not. Their difference realizes the first apotome rather than assuming such a line exists.","square numbers ED and EF","first apotome");
const scene86=constructApotome(86,"Construct the second apotome by reversing the square ratio.","The same nonsquare numerical difference is placed in the reciprocal square relation. Reversing that ratio changes the associated difference condition and yields the second apotome.","reciprocal square ratio FD : DE","second apotome");
const scene87=constructApotome(87,"Construct the third apotome from two linked square ratios.","Three numerical magnitudes supply two consecutive square ratios. The constructed rational terms are square-commensurable only, and their prescribed difference yields the third apotome.","two linked nonsquare ratios","third apotome");
const scene88=constructApotome(88,"Construct the fourth apotome from a whole-to-part square ratio.","The numerical whole and each part avoid a square-number ratio. Transferring whole-to-part data to two squares produces the fourth apotome's distinct difference condition.","whole DE : part EF","fourth apotome");
const scene89=constructApotome(89,"Construct the fifth apotome using the complementary part ratio.","This construction reverses the whole-to-part relation from X.88. The same rational square-commensurable-only terms now carry the fifth apotome's auxiliary condition.","part FE : whole ED","fifth apotome");
const scene90=constructApotome(90,"Construct the sixth apotome from two incompatible linked ratios.","Both consecutive numerical ratios avoid square-number ratios. The resulting rational terms are square-commensurable only but satisfy the final distinct difference condition.","two incompatible linked ratios","sixth apotome");
const scene91=correspondence(91,"A rational rectangle on a first apotome has an apotome as square side.","Apply the area to a rational line. The square side inherits the first subtraction class as an apotome, giving a precise area-to-side correspondence.","first apotome","rational rectangle","apotome");
const scene92=correspondence(92,"A rational rectangle on a second apotome has a first medial apotome as square side.","The second-apotome input maps one step into the medial-apotome chain under the rational-area construction.","second apotome","rational rectangle","first apotome of medial");
const scene93=correspondence(93,"A rational rectangle on a third apotome has a second medial apotome as square side.","The third apotome maps to the second medial apotome. The names are kept as source and target rather than being presented as interchangeable irrationality.","third apotome","rational rectangle","second apotome of medial");
const scene94=correspondence(94,"A rational rectangle on a fourth apotome has a minor square side.","The fourth apotome's square relation transforms specifically into minor under application to a rational line.","fourth apotome","rational rectangle","minor");
const scene95=correspondence(95,"A rational rectangle on a fifth apotome has a rational-area medial-whole square side.","The fifth member of the apotome family maps to the named line producing with a rational area a medial whole.","fifth apotome","rational rectangle","rational-area medial whole");
const scene96=correspondence(96,"A rational rectangle on a sixth apotome has a medial-area medial-whole square side.","The final apotome class maps to the final named difference class under the same rational-area operation.","sixth apotome","rational rectangle","medial-area medial whole");
const scene97=correspondence(97,"The square on an apotome produces a first apotome as breadth.","Applying the apotome's square to a rational line reverses the first area-to-side correspondence: the produced breadth is first apotome.","apotome square","apply to rational line","first apotome");
const scene98=correspondence(98,"The square on a first medial apotome produces a second apotome as breadth.","This is the inverse step paired with X.92: first medial apotome square leads to second apotome breadth.","first medial apotome square","apply to rational line","second apotome");
const scene99=correspondence(99,"The square on a second medial apotome produces a third apotome as breadth.","The second medial-apotome square maps back to the third apotome, preserving the ordered correspondence.","second medial apotome square","apply to rational line","third apotome");
const scene100=correspondence(100,"The square on a minor produces a fourth apotome as breadth.","Minor's square applied to a rational line yields exactly the fourth apotome; it is the reciprocal of X.94.","minor square","apply to rational line","fourth apotome");
const scene101=correspondence(101,"The rational-area medial-whole square produces a fifth apotome as breadth.","Applying this named square to a rational line returns the fifth apotome, closing the reciprocal pair with X.95.","rational-area medial-whole square","apply to rational line","fifth apotome");
const scene102=correspondence(102,"The medial-area medial-whole square produces a sixth apotome as breadth.","Applying the final named square to a rational line returns the sixth apotome, the exact reciprocal correspondence to the area-to-side statement in X.96.","medial-area medial-whole square","apply to rational line","sixth apotome");
const scene103=classPreserved(103,"A commensurable line with an apotome is an apotome of the same order.","Scaling the apotome's two rational terms by the same common measure preserves their difference and all order-defining relations.","apotome","apotome");
const scene104=classPreserved(104,"A commensurable line with a medial apotome preserves its medial-apotome order.","The common scale preserves both the subtraction form and the rational-or-medial rectangle condition that determines the order.","apotome of medial","apotome of medial");
const scene105=classPreserved(105,"A commensurable line with a minor remains minor.","The minor's rational sum of squares and medial rectangle scale together under a common measure, leaving the class intact.","minor","minor");
const scene106=classPreserved(106,"A commensurable line with the rational-area medial-whole class remains in that class.","A rational length factor cannot change the mixed rational/medial composite-area condition defining this named line, so the class is retained under commensurable scaling.","rational-area medial whole","rational-area medial whole");
const scene107=classPreserved(107,"A commensurable line with the medial-area medial-whole class remains in that class.","The fully medial and incommensurable composite-area relation survives common scaling without changing its name.","medial-area medial whole","medial-area medial whole");
const scene108=alternatives(108,"Rational area minus medial area produces an apotome or minor square side.","The rational whole and medial subtraction lead to two possible square-side classes. The visual keeps the branch explicit because the proposition does not merge them.","rational area − medial area",["apotome","minor"]);
const scene109=alternatives(109,"Medial area minus rational area produces two other named square sides.","Reversing the rational and medial roles changes the permitted outcomes. The square side is either a first medial apotome or a rational-area medial-whole line.","medial area − rational area",["first apotome of medial","rational-area medial whole"]);
const scene110=alternatives(110,"Medial area minus incommensurable medial area produces the final two classes.","When both areas are medial and the removed one is incommensurable with the whole, the square side is either a second medial apotome or a medial-area medial-whole line.","medial area − incommensurable medial area",["second apotome of medial","medial-area medial whole"]);
const scene111=scene(111,"An apotome is a difference, not a binomial sum.","The same kinds of rational, square-commensurable-only terms can be combined by subtraction or addition. The direction of composition is structural: it separates apotome from binomial.",["Set out the same two terms","Subtract for an apotome; add for a binomial","Keep the two named lines distinct"],()=>[rect(90,90,170,32,"area",0),rect(260,90,140,32,"area-secondary",0),label(175,80,"two rational terms", "line",0),line(90,185,260,185,"result",1),label(175,215,"apotome = larger − smaller", "result",1),line(90,280,400,280,"construction",2),label(245,310,"binomial = larger + smaller", "construction",2)],"The difference and sum are distinct irrational lines",()=>true);
const scene112=scene(112,"Applying a rational square to a binomial produces a corresponding apotome.","The construction puts a rational square on a binomial as an applied area. The resulting breadth subtracts corresponding terms in the same ratio, and retains the binomial's order.",["Set out binomial terms in ratio a:b","Apply a square on a rational line","Read proportional apotome terms"],()=>[rect(80,82,185,38,"area",0),rect(265,82,135,38,"area-secondary",0),label(240,72,"binomial terms a + b", "line",0),rect(110,175,290,88,"construction",1),label(255,225,"rational square applied", "construction",1),line(115,315,270,315,"result",2),label(192,345,"apotome terms ka − kb", "result",2)],"Apotome terms are commensurable and in the same ratio",()=>true);
const scene113=scene(113,"Applying a rational square to an apotome produces a corresponding binomial.","This reverses X.112. The rational-square construction turns proportional difference terms into sum terms while preserving their ratio and the common order.",["Set out apotome terms in ratio a:b","Apply a square on a rational line","Read proportional binomial terms"],()=>[line(100,105,255,105,"area",0),label(177,85,"apotome terms a − b", "line",0),rect(110,175,290,88,"construction",1),label(255,225,"rational square applied", "construction",1),line(100,315,390,315,"result",2),label(245,345,"binomial terms ka + kb", "result",2)],"Binomial terms are commensurable and in the same ratio",()=>true);
const scene114=scene(114,"Corresponding apotome and binomial terms contain a rational area.","The apotome's terms and the binomial's corresponding proportional terms form a rectangle. The paired sum-and-difference relations cancel the irrational cross-terms, leaving a rational square side.",["Align corresponding terms in the same ratio","Form the contained rectangle","Read the rational square side"],()=>[rect(100,80,220,125,"area",0),label(210,145,"apotome × matching binomial", "line",0),rect(350,115,120,90,"area-secondary",1),label(410,165,"cross-terms cancel", "construction",1),label(305,300,"contained area has a rational square side", "result",2)],"The contained area is rational",()=>true);
const scene115=scene(115,"A medial line generates infinitely many distinct irrational lines.","Starting from one medial line, Euclid's constructions generate new named and unnamed irrational lines. The chain does not cycle back to an earlier irrational, so the supply is infinite.",["Start from a medial line","Apply successive irrational constructions","Each result differs from every earlier line"],()=>[line(85,110,205,110,"given",0),label(145,88,"medial", "given",0),line(225,110,345,165,"construction",1),line(225,110,345,55,"construction",1),label(390,55,"new irrational 1", "construction",1),label(390,175,"new irrational 2", "construction",1),line(345,55,485,55,"result",2),line(345,165,485,250,"result",2),label(500,55,"distinct", "result",2),label(500,255,"and onward …", "result",2)],"Infinitely many irrational lines arise, none repeated",()=>true);
